jQuery(document).ready(function(t){t.ajax({url:tpayThankYou.url,method:"POST",data:{action:"tpay_blik0_transaction_status",transactionId:tpayThankYou.transactionId,nonce:tpayThankYou.nonce},success:function(s){switch(s.status){case"correct":t("#tpay_pending").css("display","none"),t("#tpay_success").css("visibility","visible");break;case"pending":null!==s.payments.attempts.pop().paymentErrorCode?(t("#tpay_pending").css("display","none"),t("#tpay_error").css("visibility","visible")):setTimeout(t.ajax(this),1500)}},error:function(s){t("#tpay_pending").css("display","none"),t("#tpay_error").css("visibility","visible")}})});